import{_ as o,o as n,c as a,ae as i}from"./chunks/framework.CyZiF_rV.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ru/offline/automatyczne-okreslanie-trybu-offline.md","filePath":"ru/offline/automatyczne-okreslanie-trybu-offline.md"}'),t={name:"ru/offline/automatyczne-okreslanie-trybu-offline.md"};function l(r,e,c,f,d,s){return n(),a("div",null,[...e[0]||(e[0]=[i('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/offline/automatyczne-okreslanie-trybu-offline.md" target="_blank" rel="noreferrer">offline/automatyczne-okreslanie-trybu-offline.md</a></p></blockquote><h2 id="автоматическое-определение-режима-отправки-offline" tabindex="-1">Автоматическое определение режима отправки offline <a class="header-anchor" href="#автоматическое-определение-режима-отправки-offline" aria-label="Permalink to &quot;Автоматическое определение режима отправки offline&quot;">​</a></h2><p>04.10.2025</p><p>В случае счетов-фактур, отправляемых как online (<code>offlineMode: false</code>), система KSeF может присвоить им режим offline - на основе сравнения даты выставления с датой принятия к обработке.</p><h2 id="алгоритм-механизма" tabindex="-1">Алгоритм механизма <a class="header-anchor" href="#алгоритм-механизма" aria-label="Permalink to &quot;Алгоритм механизма&quot;">​</a></h2><p>Для счетов-фактур, отправляемых как <code>offlineMode: false</code>, система сравнивает:</p><ul><li><strong>дату выставления</strong> счета-фактуры (<code>issueDate</code>, например, <code>P_1</code> для счета-фактуры, соответствующего FA(3)),</li><li><strong>дату принятия</strong> счета-фактуры в системе KSeF для дальнейшей обработки (<code>invoicingDate</code>).</li></ul><p>Правила:</p><ul><li>Если календарный день из <code>issueDate</code> раньше календарного дня из <code>invoicingDate</code> (сравнение по дате, не по времени), система автоматически отмечает счет-фактуру как <strong>offline</strong>, даже если она не была так заявлена.</li><li>Если день <code>issueDate</code> и день <code>invoicingDate</code> одинаковы, счет-фактура остается <strong>online</strong>.</li></ul><p>Значение <code>invoicingDate</code> зависит от режима отправки:</p><ul><li><strong>пакетная сессия</strong> - <code>invoicingDate</code> - это момент открытия сессии (равен <code>dateCreated</code>, возвращаемому в статусе сессии - GET <code>/sessions/{referenceNumber}</code>),</li><li><strong>интерактивная сессия</strong> - <code>invoicingDate</code> - это момент отправки счета-фактуры.</li></ul><p>Это означает, что если, например, счет-фактура была выставлена 2025-10-03 (<code>P_1</code>), а отправлена 2025-10-04 в 00:00:01, то несмотря на offlineMode: false она будет отмечена как счет-фактура offline.</p><h2 id="примеры" tabindex="-1">Примеры <a class="header-anchor" href="#примеры" aria-label="Permalink to &quot;Примеры&quot;">​</a></h2><p><strong>Пакетная сессия</strong> открыта в 23:59:59 3 октября: Даже если пакет будет отправлен после полуночи, счета-фактуры останутся online – поскольку <code>invoicingDate</code> - это 3 октября (дата открытия сессии).</p><p><strong>Интерактивная сессия</strong> начата в 23:59:59 3 октября, а счета-фактуры были отправлены после полуночи: Если <code>P_1</code> = 2025-10-03, система отметит их как offline – поскольку день <code>P_1</code> раньше дня отправки.</p><h2 id="связанные-документы" tabindex="-1">Связанные документы <a class="header-anchor" href="#связанные-документы" aria-label="Permalink to &quot;Связанные документы&quot;">​</a></h2><ul><li><a href="./../tryby-offline.html">Режимы offline</a></li></ul>',17)])])}const g=o(t,[["render",l]]);export{p as __pageData,g as default};
